function getComments(content, bid, cid) {
    let { java, cache, source } = this;
    try {
        // 填写评论多少的气泡
        let apiUrl = `https://fanqie.acgkami.com/comment_list.php?item_id=${cid}`;
        let comments = java.ajax(apiUrl);
        let lines = content.split("\n");
        let raw = JSON.parse(comments).data.data;
        Object.keys(raw).forEach((x) => {
            if (x < lines.length) {
                cache.putMemory(`fq-${bid}-${cid}-${x}-text`, lines[x]);
                let color = "red";            
                lines[x] += `<img src="${this.createSvg(raw[x].count, color, bid, cid, x)}">`;
            };
        });

        let chapterDiscussionSvg = this.createChapterDiscussionSvg(bid, cid);
        lines.push(`<img src="${chapterDiscussionSvg}">`);

        return lines.join("\n");
    } catch (e) {
        return content;
    }
}

// 自定义随机气泡数字
function getraw(length) {
    const { java, source } = this;
    let result = {};
    for (let i = 0; i < length; i++) {
        result[i] = { count: Math.floor(Math.random() * 100) + 1 };
    }
    return result;
}

function createSvg(number, color, bid, cid, para) {
    var displayText = number > 99 ? "99+" : number;
    var date = String(Date.now()).match(/(\d{6}$)/)[1];
    var svg;
    svg = '<svg width="1000" height="909" xmlns="http://www.w3.org/2000/svg">' +
          '<path d="M80,80 h840 a60,60 0 0 1 60,60 v580 a60,60 0 0 1 -60,60 h-620 l-140,90 v-90 h-80 a60,60 0 0 1 -60,-60 v-580 a60,60 0 0 1 60,-60 z" ' +
          'fill="none" stroke="' + color + '" stroke-width="16" stroke-linejoin="round"/>' +
          '<text x="500" y="450" font-family="Arial, sans-serif" text-anchor="middle" ' +
          'font-size="360" fill="' + color + '" dy="0.3em">' + displayText + '</text>' +
          '</svg>';

    var encodedSvg = this.java.base64Encode(svg);
    return 'data:image/svg+xml;base64,' + encodedSvg + ',{"js":"showCmt(\'' + bid + '\',\'' + cid + '\',\'' + para + '\',\'' + date + '\')","style":"text"}';
}

function showCmt(bid, cid, para, date) {
    let { java, cache, cookie, source } = this;
    let mname = `fq-${bid}-${cid}-${para}`;
    let load = (cache.getFromMemory(mname) ?? "-").split("-");

    if (load[0] != "1" || load[1] != date) {
        cache.putMemory(mname, "1-" + date);
        //java.toast("跳过加载");
        return;
    }
    // 评论显示的html 
    let apiUrl = `https://fanqie.acgkami.com/comments.html?book_id=${bid}&item_id=${cid}&para_index=${para}`;
    let title = cache.getFromMemory(mname + "-text") ?? "段评内容";

    java.startBrowser(apiUrl, title);
}

function createChapterDiscussionSvg(bid, cid) {
    const displayText = "本章讨论";
    const date = String(Date.now()).match(/(\d{6}$)/)[1];
    const svg = `<svg width="1000" height="120" xmlns="http://www.w3.org/2000/svg"><rect width="1000" height="120" fill="#A9A9A9" rx="15"/><text x="120" y="75" font-family="Arial" font-size="48" fill="#000000" text-anchor="middle">${displayText}</text><text x="965" y="75" font-family="Arial" font-size="36" fill="#000000" text-anchor="middle">〉</text></svg>`;
    const encodedSvg = this.java.base64Encode(svg);
    return 'data:image/svg+xml;base64,' + encodedSvg + ',{"js":"showChapterDiscussion(\'' + bid + '\',\'' + cid + '\',\'' + date + '\')","style":"full"}';
}


function showChapterDiscussion(bid, cid, date) {
    let { java, cache, cookie, source } = this;
    let mname = `fq-${bid}-${cid}`;
    let load = (cache.getFromMemory(mname) ?? "-").split("-");

