function removeChapterTitleLines(text) {
    const regex = /^第\s*[零一二三四五六七八九十百千万亿\d]+\s*章\s*[:：]?\s*.*$/gm;
    let clean = text.replace(regex, '').replace(/\n\s*\n/g, '\n').trim();
    return clean;
}

