function cleanTitleAdvanced(title) {
  const parts = title.split(/\s*/);
  const uniqueParts = [];
  const seen = new Set();

  for (const part of parts) {
    if (/^第\d+章$/.test(part) && seen.has(part)) {
      continue;
    }
    uniqueParts.push(part);
    seen.add(part);
  }

  return uniqueParts.join(" ");
}

